    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, files, mask } = options;
    const warnings: SharedV3Warning[] = [];

    // Warn for unsupported standard options
    if (aspectRatio != null) warnings.push({ type: 'unsupported', feature: 'aspectRatio', details: 'PixelArt does not support `aspectRatio`. Use `size` instead.' });
    if (seed != null) warnings.push({ type: 'unsupported', feature: 'seed', details: 'PixelArt does not support the `seed` option.' });
    if (files != null && files.length > 0) warnings.push({ type: 'unsupported', feature: 'image editing', details: 'PixelArt does not support image editing via files.' });
    if (mask != null) warnings.push({ type: 'unsupported', feature: 'mask', details: 'PixelArt does not support mask-based image editing.' });

    // Parse provider-specific options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        model: this.modelId,
        n: n ?? 1,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.size != null ? { size: pixelartOptions.size } : {}),
        ...(pixelartOptions?.style != null ? { style: pixelartOptions.style } : {}),
        ...(pixelartOptions?.pixelDensity != null ? { pixel_density: pixelartOptions.pixelDensity } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: (error) => error.error?.message ?? 'Unknown PixelArt API error',
      }),
      successfulResponseHandler: createJsonResponseHandler(pixelartImageResponseSchema),
    });

    return {
      images: response.data.map((item) => convertBase64ToUint8Array(item.b64_json)),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema — minimal, uses .nullish() for flexibility
