### Step 8 — `packages/pixelart/src/pixelart-image-model.ts`

The core image model implementing `ImageModelV3`. Key design:
- Accepts `modelId` + config in constructor
- `doGenerate()` POSTs to `${baseURL}/images/generate`
- Reads provider-specific options via `parseProviderOptions({ provider: 'pixelart', ... })`
- Maps standard `size` param and provider options (`style`, `pixelDensity`) into request body
- Warns (does not throw) for unsupported standard params: `aspectRatio`, `seed`
- Warns for unsupported `files`/`mask` (no image editing)
- Returns images as `Uint8Array` (decoded from `b64_json`)
- Uses `lazySchema` + `zodSchema` + `z` from `zod/v4` for response validation
- Uses `createJsonErrorResponseHandler` for error handling

```typescript
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  InferSchema,
  combineHeaders,
  convertBase64ToUint8Array,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';

// Internal config type (not exported)
interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  _internal?: { currentDate?: () => Date };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string { return this.config.provider; }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(options: Parameters<ImageModelV3['doGenerate']>[0]):
    Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {

    const { prompt, n, size, aspectRatio, seed, providerOptions, headers, abortSignal, files, mask } = options;
    const warnings: SharedV3Warning[] = [];

    // Warn for unsupported standard options
    if (aspectRatio != null) warnings.push({ type: 'unsupported', feature: 'aspectRatio', details: 'PixelArt does not support `aspectRatio`. Use `size` instead.' });
    if (seed != null) warnings.push({ type: 'unsupported', feature: 'seed', details: 'PixelArt does not support the `seed` option.' });
    if (files != null && files.length > 0) warnings.push({ type: 'unsupported', feature: 'image editing', details: 'PixelArt does not support image editing via files.' });
    if (mask != null) warnings.push({ type: 'unsupported', feature: 'mask', details: 'PixelArt does not support mask-based image editing.' });

    // Parse provider-specific options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelartImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        prompt,
        model: this.modelId,
        n: n ?? 1,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.size != null ? { size: pixelartOptions.size } : {}),
        ...(pixelartOptions?.style != null ? { style: pixelartOptions.style } : {}),
        ...(pixelartOptions?.pixelDensity != null ? { pixel_density: pixelartOptions.pixelDensity } : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelartErrorSchema,
        errorToMessage: (error) => error.error?.message ?? 'Unknown PixelArt API error',
      }),
      successfulResponseHandler: createJsonResponseHandler(pixelartImageResponseSchema),
    });

    return {
      images: response.data.map((item) => convertBase64ToUint8Array(item.b64_json)),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema — minimal, uses .nullish() for flexibility
const pixelartImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema
const pixelartErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    type: z.string().nullish(),
    code: z.string().nullish(),
  }).nullish(),
});

// Provider options schema — restrictive, uses .optional()
export const pixelartImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      size: z.string().optional(),
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      pixelDensity: z.number().optional(),
    }).passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelartImageModelOptionsSchema>;
```

