import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  postJsonToApi,
  InferSchema,
  lazySchema,
  parseProviderOptions,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: string,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'This model does not support the `aspectRatio` option.',
      });
    }

    if (seed != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'seed',
        details: 'This model does not support the `seed` option.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image',
        details: 'This model does not support image editing via input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'This model does not support mask-based inpainting.',
      });
    }

    // Parse and validate provider options
    const pixelartOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n: n ?? 1,
        ...(size != null ? { size } : {}),
        ...(pixelartOptions?.size != null
          ? { size: pixelartOptions.size }
          : {}),
        ...(pixelartOptions?.style != null
          ? { style: pixelartOptions.style }
          : {}),
        ...(pixelartOptions?.pixelDensity != null
          ? { pixel_density: pixelartOptions.pixelDensity }
          : {}),
      },
      abortSignal,
      fetch: this.config.fetch,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: pixelArtErrorSchema,
        errorToMessage: (error: PixelArtErrorData) =>
          error.message ?? 'Unknown error',
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
    });

    return {
      images: response.data.map(item => {
        const binary = atob(item.b64_json);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) {
          bytes[i] = binary.charCodeAt(i);
        }
        return bytes;
      }),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

// Response schema for the PixelArt image generation API
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema for the PixelArt API
const pixelArtErrorSchema = z.object({
  message: z.string().nullish(),
  code: z.string().nullish(),
});

export type PixelArtErrorData = z.infer<typeof pixelArtErrorSchema>;

/**
 * Provider options schema for PixelArt image generation.
 */
export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z
      .object({
        /**
         * The desired output size of the generated image (e.g. "512x512").
         */
        size: z.string().nullish(),

        /**
         * The pixel art style to apply.
         *
         * - `pixel`: Classic pixel art style.
         * - `retro`: Retro-inspired style with limited color palette.
         * - `8bit`: 8-bit era video game aesthetic.
         */
        style: z.enum(['pixel', 'retro', '8bit']).nullish(),

        /**
         * The density of pixels in the output image.
         */
        pixelDensity: z.number().nullish(),
      })
      .passthrough(),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

